// ---- Helpers ----

function makeRecord(overrides: Partial<TokenUsage> = {}): TokenUsage {
	return {
		timestamp: new Date(),
		model: "claude-sonnet-4-5",
		sessionId: "test-session",
		inputTokens: 1000,
		outputTokens: 500,
		cacheCreationTokens: 0,
		cacheReadTokens: 0,
		cacheCreation5m: 0,
		cacheCreation1h: 0,
		cost: 0.01,
		...overrides,
	};
}

function emptyBuckets(): TimeBuckets {
	return {
		session: new Map(),
		daily: new Map(),
		weekly: new Map(),
		monthly: new Map(),
		modelWeekly: new Map(),
		hourly: new Map(),
	};
}

function makeAgg(overrides: Partial<AggregatedUsage> = {}): AggregatedUsage {
	return {
		inputTokens: 0,
		outputTokens: 0,
		cacheCreationTokens: 0,
		cacheReadTokens: 0,
		totalCost: 0,
		messageCount: 0,
		firstMessage: null,
		lastMessage: null,
		...overrides,
	};
}

// ==================================================================
// TEST: 5-hour session window over-counts lifetime output tokens
// ==================================================================

describe("calculateRateLimits - 5hr session window", () => {
	it("CRITICAL: should NOT count tokens from messages older than 5 hours in session total", () => {
		const now = new Date();
		const buckets = emptyBuckets();

		// Session that started 8 hours ago, last message 1 hour ago
		// Total lifetime: 100K output tokens
		// Tokens in last 5 hours: ~40K (estimated, but code can't distinguish)
		buckets.session.set(
			"long-session",
			makeAgg({
				outputTokens: 100_000,
				firstMessage: subHours(now, 8),
				lastMessage: subHours(now, 1),
			}),
		);

		const result = calculateRateLimits(buckets, "max5");

		// BUG: The code counts ALL 100K because lastMessage is within 5hrs.
		// Correct behavior: should only count tokens with timestamps in the window.
		// This test documents the bug. It will FAIL with current code:
		expect(result.session5h.currentTokens).toBeLessThan(100_000);
		// Current code returns 100_000 (the full session lifetime)
	});

	it("should correctly count sessions entirely within the 5hr window", () => {
		const now = new Date();
		const buckets = emptyBuckets();

		// Short session, fully within 5hr window
		buckets.session.set(
			"short-session",
			makeAgg({
				outputTokens: 20_000,
				firstMessage: subHours(now, 2),
				lastMessage: subMinutes(now, 30),
			}),
		);

		const result = calculateRateLimits(buckets, "max5");
		expect(result.session5h.currentTokens).toBe(20_000);
	});

	it("should exclude sessions with lastMessage older than 5 hours", () => {
		const now = new Date();
		const buckets = emptyBuckets();

		buckets.session.set(
			"old-session",
			makeAgg({
				outputTokens: 50_000,
				firstMessage: subHours(now, 10),
				lastMessage: subHours(now, 6),
			}),
		);

		const result = calculateRateLimits(buckets, "max5");
		expect(result.session5h.currentTokens).toBe(0);
	});
});

// ==================================================================
// TEST: mergeTimeBuckets should not mutate source operand
// ==================================================================

describe("mergeTimeBuckets - immutability", () => {
	it("CRITICAL: merging should not mutate the first operand's AggregatedUsage values", () => {
		const a = emptyBuckets();
		a.daily.set(
			"2026-03-07",
			makeAgg({ outputTokens: 1000, inputTokens: 500 }),
		);

		const b = emptyBuckets();
		b.daily.set(
			"2026-03-07",
			makeAgg({ outputTokens: 2000, inputTokens: 1000 }),
		);

		// Capture original values
		const originalAOutputTokens = a.daily.get("2026-03-07")!.outputTokens;

		const merged = mergeTimeBuckets(a, b);

		// merged should have combined values
		expect(merged.daily.get("2026-03-07")!.outputTokens).toBe(3000);

		// BUG: a's values should be unchanged, but mergeTimeBuckets mutates them
		// via shallow Map copy + in-place addition
		expect(a.daily.get("2026-03-07")!.outputTokens).toBe(originalAOutputTokens);
		// Current code: a.daily.get("2026-03-07")!.outputTokens === 3000 (mutated!)
	});

	it("should produce independent copies for non-overlapping keys", () => {
		const a = emptyBuckets();
		a.daily.set("2026-03-06", makeAgg({ outputTokens: 500 }));

		const b = emptyBuckets();
		b.daily.set("2026-03-07", makeAgg({ outputTokens: 700 }));

		const merged = mergeTimeBuckets(a, b);

		// Mutate merged - should not affect a
		merged.daily.get("2026-03-06")!.outputTokens = 9999;
		expect(a.daily.get("2026-03-06")!.outputTokens).toBe(500);
	});
});

// ==================================================================
// TEST: CRLF offset calculation
// ==================================================================

describe("incrementalParser - byte offset tracking", () => {
	// This is a design-level test documenting the CRLF bug.
	// The actual incrementalParser reads from disk, so this tests the math.
	it("HIGH: byte offset should account for CRLF (2 bytes) not just LF (1 byte)", () => {
		// Simulate the offset calculation for a CRLF line
		const line =
			'{"type":"assistant","timestamp":"2026-03-07T00:00:00Z","sessionId":"s1","message":{"model":"claude-sonnet-4-5","usage":{"input_tokens":100,"output_tokens":50}}}';
		const lineBytes = Buffer.byteLength(line, "utf8");

		// Current code: bytesRead += lineBytes + 1 (assumes \n)
		const offsetWithLF = lineBytes + 1;

		// Correct for CRLF: bytesRead += lineBytes + 2
		const offsetWithCRLF = lineBytes + 2;

		// The difference accumulates: after 1000 lines, offset is 1000 bytes off
		const linesInFile = 1000;
		const driftAfter1000Lines =
			linesInFile * offsetWithCRLF - linesInFile * offsetWithLF;
		expect(driftAfter1000Lines).toBe(1000);
		// 1000 bytes of drift = starts mid-line on next incremental parse
	});
});

