// ==================================================================
// TEST: Burn rate with EMA should handle edge cases
// ==================================================================

describe("calculateBurnRateEMA - edge cases", () => {
	it("should return 0 when no sessions have recent activity", () => {
		const buckets = emptyBuckets();
		buckets.session.set(
			"old",
			makeAgg({
				outputTokens: 50000,
				firstMessage: subHours(new Date(), 10),
				lastMessage: subHours(new Date(), 8),
			}),
		);

		const tracker = createBurnRateTracker();
		const result = calculateBurnRateEMA(buckets, tracker, 15);
		expect(result.rate).toBe(0);
	});

	it("should produce positive rate with active session", () => {
		const now = new Date();
		const buckets = emptyBuckets();
		buckets.session.set(
			"active",
			makeAgg({
				outputTokens: 10000,
				firstMessage: subMinutes(now, 10),
				lastMessage: subMinutes(now, 1),
			}),
		);

		const tracker = createBurnRateTracker();
		const result = calculateBurnRateEMA(buckets, tracker, 15);
		expect(result.rate).toBeGreaterThan(0);
	});

	it("EMA should smooth across multiple calculations", () => {
		const now = new Date();
		const buckets = emptyBuckets();
		buckets.session.set(
			"active",
			makeAgg({
				outputTokens: 10000,
				firstMessage: subMinutes(now, 10),
				lastMessage: subMinutes(now, 1),
			}),
		);

		let tracker = createBurnRateTracker(0.5);
		const result1 = calculateBurnRateEMA(buckets, tracker, 15);
		tracker = result1.tracker;

		// Double the tokens
		buckets.session.get("active")!.outputTokens = 20000;
		const result2 = calculateBurnRateEMA(buckets, tracker, 15);

		// EMA should be between the two raw rates (smoothed)
		expect(result2.rate).toBeGreaterThan(result1.rate);
	});
});

// ==================================================================
// TEST: aggregateUsage correctness
// ==================================================================

describe("aggregateUsage", () => {
	it("should correctly aggregate multiple records into time buckets", () => {
		const records = [
			makeRecord({
				timestamp: new Date("2026-03-07T10:00:00Z"),
				outputTokens: 100,
				sessionId: "s1",
			}),
			makeRecord({
				timestamp: new Date("2026-03-07T11:00:00Z"),
				outputTokens: 200,
				sessionId: "s1",
			}),
			makeRecord({
				timestamp: new Date("2026-03-07T12:00:00Z"),
				outputTokens: 300,
				sessionId: "s2",
			}),
		];

		const buckets = aggregateUsage(records);

		// Session aggregation
		expect(buckets.session.size).toBe(2);
		expect(buckets.session.get("s1")!.outputTokens).toBe(300);
		expect(buckets.session.get("s2")!.outputTokens).toBe(300);
		expect(buckets.session.get("s1")!.messageCount).toBe(2);

		// Daily aggregation
		expect(buckets.daily.size).toBe(1);
		const daily = Array.from(buckets.daily.values())[0];
		expect(daily.outputTokens).toBe(600);
	});

	it("should handle empty records array", () => {
		const buckets = aggregateUsage([]);
		expect(buckets.session.size).toBe(0);
		expect(buckets.daily.size).toBe(0);
	});
});
